566	     * @return bool
567	     *
568	     * @phpstan-assert-if-true class-string<\Illuminate\Contracts\Queue\ShouldQueue> $class
569	     */
570	    protected function handlerShouldBeQueued($class)
571	    {
572	        try {
573	            return (new ReflectionClass($class))->implementsInterface(
