581	    /**
582	     * Create a callable for putting an event handler on the queue.
583	     *
584	     * @param  class-string  $class
585	     * @param  string  $method
586	     * @return \Closure(): void
587	     */
588	    protected function createQueuedHandlerCallable($class, $method)
589	    {
590	        return function () use ($class, $method) {
591	            $arguments = array_map(function ($a) {
592	                return is_object($a) ? clone $a : $a;
593	            }, func_get_args());
594	
595	            if ($this->handlerWantsToBeQueued($class, $arguments)) {
596	                $this->queueHandler($class, $method, $arguments);
597	            }
598	        };
599	    }
