601	    /**
602	     * Determine if the given event handler should be dispatched after all database transactions have committed.
603	     *
604	     * @param  mixed  $listener
605	     * @return bool
606	     */
607	    protected function handlerShouldBeDispatchedAfterDatabaseTransactions($listener)
608	    {
609	        return (($listener->afterCommit ?? null) ||
610	                $listener instanceof ShouldHandleEventsAfterCommit) &&
611	                $this->resolveTransactionManager();
612	    }
