614	    /**
615	     * Create a callable for dispatching a listener after database transactions.
616	     *
617	     * @param  mixed  $listener
618	     * @param  string  $method
619	     * @return \Closure
620	     */
621	    protected function createCallbackForListenerRunningAfterCommits($listener, $method)
622	    {
623	        return function () use ($method, $listener) {
624	            $payload = func_get_args();
625	
626	            $this->resolveTransactionManager()->addCallback(
627	                function () use ($listener, $method, $payload) {
628	                    $listener->$method(...$payload);
629	                }
630	            );
631	        };
632	    }
