634	    /**
635	     * Determine if the event handler wants to be queued.
636	     *
637	     * @param  class-string  $class
638	     * @param  array  $arguments
639	     * @return bool
640	     */
641	    protected function handlerWantsToBeQueued($class, $arguments)
642	    {
643	        $instance = $this->container->make($class);
644	
645	        if (method_exists($instance, 'shouldQueue')) {
646	            return $instance->shouldQueue($arguments[0]);
647	        }
648	
649	        return true;
650	    }
