652	    /**
653	     * Queue the handler class.
654	     *
655	     * @param  string  $class
656	     * @param  string  $method
657	     * @param  array  $arguments
658	     * @return void
659	     */
660	    protected function queueHandler($class, $method, $arguments)
661	    {
662	        [$listener, $job] = $this->createListenerAndJob($class, $method, $arguments);
663	
664	        if ($job->shouldBeUnique &&
665	            ! (new UniqueLock($this->container->make(Cache::class)))->acquire($job)) {
666	            return;
667	        }
668	
669	        $connectionName = method_exists($listener, 'viaConnection')
670	            ? (isset($arguments[0]) ? $listener->viaConnection($arguments[0]) : $listener->viaConnection())
671	            : $this->getAttributeValue($listener, Connection::class, 'connection');
672	
673	        $connection = $this->resolveQueue()->connection(
674	            $connectionName ?? $this->resolveConnectionFromQueueRoute($listener) ?? null
675	        );
676	
677	        $queue = method_exists($listener, 'viaQueue')
678	            ? (isset($arguments[0]) ? $listener->viaQueue($arguments[0]) : $listener->viaQueue())
679	            : $this->getAttributeValue($listener, QueueAttribute::class, 'queue');
680	
681	        $delay = method_exists($listener, 'withDelay')
682	            ? (isset($arguments[0]) ? $listener->withDelay($arguments[0]) : $listener->withDelay())
683	            : $this->getAttributeValue($listener, Delay::class, 'delay');
684	
685	        if (is_null($queue)) {
686	            $queue = $this->resolveQueueFromQueueRoute($listener) ?? null;
687	        }
688	
689	        is_null($delay)
690	            ? $connection->pushOn(enum_value($queue), $job)
691	            : $connection->laterOn(enum_value($queue), $delay, $job);
692	    }
