694	    /**
695	     * Create the listener and job for a queued listener.
696	     *
697	     * @template TListener
698	     *
699	     * @param  class-string<TListener>  $class
700	     * @param  string  $method
701	     * @param  array  $arguments
702	     * @return array{TListener, mixed}
703	     *
704	     * @throws \ReflectionException
705	     */
706	    protected function createListenerAndJob($class, $method, $arguments)
707	    {
708	        $listener = (new ReflectionClass($class))->newInstanceWithoutConstructor();
709	
710	        return [$listener, $this->propagateListenerOptions(
711	            $listener, new CallQueuedListener($class, $method, $arguments)
712	        )];
713	    }
