715	    /**
716	     * Propagate listener options to the job.
717	     *
718	     * @param  mixed  $listener
719	     * @param  \Illuminate\Events\CallQueuedListener  $job
720	     * @return \Illuminate\Events\CallQueuedListener
721	     */
722	    protected function propagateListenerOptions($listener, $job)
723	    {
724	        return tap($job, function ($job) use ($listener) {
725	            $data = array_values($job->data);
726	
727	            if ($listener instanceof ShouldQueueAfterCommit) {
728	                $job->afterCommit = true;
729	            } else {
730	                $job->afterCommit = property_exists($listener, 'afterCommit') ? $listener->afterCommit : null;
731	            }
732	
733	            $job->backoff = method_exists($listener, 'backoff') ? $listener->backoff(...$data) : $this->getAttributeValue($listener, Backoff::class, 'backoff');
734	            $job->maxExceptions = $this->getAttributeValue($listener, MaxExceptions::class, 'maxExceptions');
735	            $job->retryUntil = method_exists($listener, 'retryUntil') ? $listener->retryUntil(...$data) : null;
736	            $job->shouldBeEncrypted = $listener instanceof ShouldBeEncrypted;
737	            $job->timeout = $this->getAttributeValue($listener, Timeout::class, 'timeout');
738	            $job->failOnTimeout = $this->getAttributeValue($listener, FailOnTimeout::class, 'failOnTimeout') ?? false;
739	            $job->deleteWhenMissingModels = $this->getAttributeValue($listener, DeleteWhenMissingModels::class, 'deleteWhenMissingModels') ?? false;
740	            $job->tries = method_exists($listener, 'tries') ? $listener->tries(...$data) : $this->getAttributeValue($listener, Tries::class, 'tries');
741	            $job->messageGroup = method_exists($listener, 'messageGroup') ? $listener->messageGroup(...$data) : ($listener->messageGroup ?? null);
742	            $job->withDeduplicator(method_exists($listener, 'deduplicator')
743	                ? $listener->deduplicator(...$data)
744	                : (method_exists($listener, 'deduplicationId') ? $listener->deduplicationId(...) : null)
745	            );
746	
747	            $job->through(array_merge(
748	                method_exists($listener, 'middleware') ? $listener->middleware(...$data) : [],
749	                $listener->middleware ?? []
750	            ));
751	
752	            $job->shouldBeUnique = $listener instanceof ShouldBeUnique;
753	            $job->shouldBeUniqueUntilProcessing = $listener instanceof ShouldBeUniqueUntilProcessing;
754	
755	            if ($job->shouldBeUnique) {
756	                $job->uniqueId = method_exists($listener, 'uniqueId')
757	                    ? $listener->uniqueId(...$data)
758	                    : ($listener->uniqueId ?? null);
759	
760	                $job->uniqueFor = method_exists($listener, 'uniqueFor')
761	                    ? $listener->uniqueFor(...$data)
762	                    : ($this->getAttributeValue($listener, UniqueFor::class, 'uniqueFor') ?? 0);
763	            }
764	        });
765	    }
