848	    /**
849	     * Execute the given callback while deferring events, then dispatch all deferred events.
850	     *
851	     * @template TResult
852	     *
853	     * @param  callable(): TResult  $callback
854	     * @param  string[]|null  $events
855	     * @return TResult
856	     */
857	    public function defer(callable $callback, ?array $events = null)
858	    {
859	        $wasDeferring = $this->deferringEvents;
860	        $previousDeferredEvents = $this->deferredEvents;
861	        $previousEventsToDefer = $this->eventsToDefer;
862	
863	        $this->deferringEvents = true;
864	        $this->deferredEvents = [];
865	        $this->eventsToDefer = $events;
866	
867	        try {
868	            $result = $callback();
869	
870	            $this->deferringEvents = false;
871	
872	            foreach ($this->deferredEvents as $args) {
873	                $this->dispatch(...$args);
874	            }
875	
876	            return $result;
877	        } finally {
878	            $this->deferringEvents = $wasDeferring;
879	            $this->deferredEvents = $previousDeferredEvents;
880	            $this->eventsToDefer = $previousEventsToDefer;
881	        }
882	    }
